mapper.select:
SELECT fyje, scheduling_date, scheduling_type, scheduling_id FROM t_offline_schedulingTime s LEFT JOIN t_offline_staff a ON s.staff_code = a.staff_code LEFT JOIN t_offline_cost c ON c.`name` = s.code_name WHERE 1 = 1
and staff_name = #{map.staffName}
and code_name = #{map.codeName}
GROUP BY scheduling_id order by scheduling_date
